UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('reactive-gate-sprint', 'Two gates only; step or jog through the gate.', 'No default sex-based adjustment. Scale by first-step mechanics, cue processing, braking ability, and confidence.'),
  ('mirror-shuffle-to-sprint-exit', 'Mirror shuffle only, no sprint exit.', 'No default sex-based adjustment. Pair by size, speed, maturity, and control rather than gender alone.'),
  ('ball-drop-sprint-catch', 'Short distance, allow one or two bounces, no diving.', 'No default sex-based adjustment. Scale by acceleration, object tracking, stop control, and risk tolerance.'),
  ('power-hurdle-to-cartwheel-round-off-entry', 'Use hurdle-to-lunge freeze, cartwheel step-over, or panel-mat cartwheel.', 'No default sex-based adjustment. Scale by tumbling skill, fear, body control, upper-body support, and landing quality.'),
  ('round-off-rebound-snap-down-to-stick', 'Do not use as Output; use cartwheel line, cartwheel step-over, and round-off shape drills.', 'No default sex-based adjustment. Scale by skill mastery, confidence, body control, upper-body support, and landing quality.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

