-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('reactive-gate-sprint', 'Reactive gate sprints train the athlete to process an external cue and convert it into a high-intent first step and acceleration. NSCA describes reaction drills as requiring athletes to identify a stimulus and respond appropriately using visual, auditory, or sensory cues while maintaining body control and technique.', 'Belongs in reactive_sprint (361) — foundational reactive Output after Skill gate reaction; pre-planned routes belong in acceleration or COD, not reactive agility.', 'Simplest high-intensity reactive sprint drill after gate reaction and deceleration foundations; before partner mirror or object-reaction Output.', 'Reactive and tumbling Output belongs while the athlete is fresh — sharp, explosive, controlled, well-spaced reps with external cues or explosive tumbling tasks. If it becomes chaotic, tired, reckless, or technically sloppy, stop or regress. Do not bury high-complexity Output under fatigue. If the route is pre-planned, classify as acceleration or COD instead of reactive agility.', 'Regress to two gates with step/jog; progress fake cues and timed gate sprints only when deceleration after the gate is controlled.'),
  ('mirror-shuffle-to-sprint-exit', 'The mirror drill creates a live information source because the follower must read the leader''s movement and match it. Adding a sprint exit makes this Output because the athlete must perceive, mirror, and transition into high-intent acceleration — a bridge from reactive agility skill into sport-like speed expression.', 'Belongs in reactive_agility_output (362) — partner read plus sprint breakout after lateral shuffle mechanics.', 'After mirror shuffle and lateral shuffle mechanics are clean; adds high-intent sprint exit to partner reactive work.', 'Reactive and tumbling Output belongs while the athlete is fresh — sharp, explosive, controlled, well-spaced reps with external cues or explosive tumbling tasks. If it becomes chaotic, tired, reckless, or technically sloppy, stop or regress. Do not bury high-complexity Output under fatigue. Do not add sprint exit if mirror base collapses or rounds exceed ~10 seconds before exit.', 'Regress to mirror shuffle only; pair by size, speed, maturity, and control with mandatory no-contact rule.'),
  ('ball-drop-sprint-catch', 'The ball drop gives a clear external object cue. The athlete must watch the object, react to the drop, accelerate, track, coordinate the catch, and decelerate. NSCA includes ball-drop reaction drills in quickness/reaction training examples.', 'Belongs in object_reaction_output (363) — visual tracking plus acceleration reaction at Output intent.', 'After ball-drop reaction Skill and sprint/deceleration foundations; before advanced object-tracking games.', 'Reactive and tumbling Output belongs while the athlete is fresh — sharp, explosive, controlled, well-spaced reps with external cues or explosive tumbling tasks. If it becomes chaotic, tired, reckless, or technically sloppy, stop or regress. Do not bury high-complexity Output under fatigue. No diving. Do not turn repeated drops into sprint conditioning.', 'Start close with generous bounce limits; progress distance and first-bounce limits only when catch and stop stay controlled.'),
  ('power-hurdle-to-cartwheel-round-off-entry', 'The tumbling hurdle sets up weight transfer and balance for the entire pass. Best Darn Gymnastics coaches the front foot to stay under the knee rather than kicking far out in front. HowToGymnastics emphasizes tight core, fast hand placement, strong snap-down, and rebound for round-off quality.', 'Belongs in tumbling_takeoff_output (364) — explosive hurdle entry after Skill tumbling foundations.', 'After hurdle-to-lunge, cartwheel, and round-off entry mechanics are technically sound; before round-off rebound Output.', 'Reactive and tumbling Output belongs while the athlete is fresh — sharp, explosive, controlled, well-spaced reps with external cues or explosive tumbling tasks. If it becomes chaotic, tired, reckless, or technically sloppy, stop or regress. Do not bury high-complexity Output under fatigue. Requires qualified coach, mat, and mastered cartwheel/round-off entry — not max power before control.', 'Regress to hurdle-to-lunge freeze or panel-mat cartwheel; progress power only when hand placement and landing stay clean.'),
  ('round-off-rebound-snap-down-to-stick', 'The round-off converts entry speed and hand-support mechanics into a powerful snap-down and rebound. HowToGymnastics describes the snap-down as the most important part: legs come together quickly, body stays tight in hollow shape, heels drive down aggressively, and rebound builds tumbling power.', 'Belongs in tumbling_rebound_output (365) — highest tumbling-output card after round-off Skill foundations.', 'Final Output tumbling card after round-off foundations and power hurdle entry; highest tumbling-output demand in the phase.', 'Reactive and tumbling Output belongs while the athlete is fresh — sharp, explosive, controlled, well-spaced reps with external cues or explosive tumbling tasks. If it becomes chaotic, tired, reckless, or technically sloppy, stop or regress. Do not bury high-complexity Output under fatigue. Not a beginner round-off drill — Output expression of already-learned mechanics only.', 'Regress to round-off snap-down shape, handstand snap-down, or cartwheel-to-snap before full rebound Output.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Reactive / tumbling Output cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'output_reactive_tumbling_readiness',
  NULL,
  'Reactive Agility & Tumbling Output without chaos',
  'High-complexity Output requires freshness, external cues, generous rest, and crisp movement — not tired shuttle games or sloppy tumbling.',
  'Final Output cluster: reactive gate sprints, mirror shuffle-to-sprint exits, ball-drop sprint catches, power hurdle tumbling entry, and round-off rebound snap-down.',
  'Reactive and tumbling Output combines perception-action, high-speed decisions, deceleration, partner/object reaction, and explosive inversion. Fatigue, poor spacing, or missing prerequisites raise collision and landing risk.',
  'Master Skill gate/ball/mirror drills and deceleration first; require safe lanes and decel zones; cap reps (~10); supervise tumbling; stop when plants, catches, or rebound quality drop.',
  'Do not program after conditioning, without external cues, with crossing gate paths, diving on ball drops, or tumbling without mat/coach — regress dose or change phase intent.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_matters = EXCLUDED.why_it_matters,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  updated_at = now();
